import asyncio
import websockets
import json
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.clients = {}
        self.inventories = defaultdict(dict)
        self.lock = asyncio.Lock()

    async def register(self, websocket, player_id):
        self.clients[player_id] = websocket
        self.inventories[player_id] = {}

    async def unregister(self, player_id):
        del self.clients[player_id]
        del self.inventories[player_id]

    async def handle_trade(self, sender_id, receiver_id, item_id):
        async with self.lock:
            if item_id in self.inventories[sender_id]:
                self.inventories[receiver_id][item_id] = self.inventories[sender_id].pop(item_id)
                await self.notify_trade(sender_id, receiver_id, item_id)

    async def notify_trade(self, sender_id, receiver_id, item_id):
        if sender_id in self.clients:
            await self.clients[sender_id].send(json.dumps({
                "action": "trade",
                "status": "success",
                "item_id": item_id,
                "to": receiver_id
            }))
        if receiver_id in self.clients:
            await self.clients[receiver_id].send(json.dumps({
                "action": "trade",
                "status": "success",
                "item_id": item_id,
                "from": sender_id
            }))

    async def handle_client(self, websocket, path):
        player_id = await websocket.recv()
        await self.register(websocket, player_id)
        try:
            async for message in websocket:
                data = json.loads(message)
                if data['action'] == 'trade':
                    await self.handle_trade(data['from'], data['to'], data['item_id'])
        finally:
            await self.unregister(player_id)

    async def main(self):
        async with websockets.serve(self.handle_client, "localhost", 8765):
            await asyncio.Future()

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.main())